async function process(incomingData, nodeData, params) {
  try {
    const { displayType = 'list', maxItems = 10, expectedSchema } = nodeData;
    const { enableFormatting = true, showMetadata = false } = params;

    if (params.enableLogging) {
      console.log(`Displaying data as ${displayType}:`, incomingData);
    }

    // ContentNode is primarily for display - it doesn't alter data
    // but it can format it for presentation purposes
    let processedData = incomingData;

    // Handle different input types
    if (!processedData) {
      // Generate sample data if no input (for preview purposes)
      processedData = generateSampleData(expectedSchema);
    } else if (typeof processedData === 'object' && !Array.isArray(processedData)) {
      // Handle REST response wrappers
      if (processedData.data && Array.isArray(processedData.data)) {
        processedData = processedData.data;
      } else if (processedData.response && Array.isArray(processedData.response)) {
        processedData = processedData.response;
      } else {
        // Single object - wrap in array for consistent display
        processedData = [processedData];
      }
    }

    // Ensure we have an array for display
    if (!Array.isArray(processedData)) {
      processedData = [];
    }

    // Limit items if specified
    if (maxItems > 0 && processedData.length > maxItems) {
      processedData = processedData.slice(0, maxItems);
    }

    // Format data based on display type
    let formattedData = processedData;

    if (enableFormatting) {
      switch (displayType) {
        case 'table':
          formattedData = formatForTable(processedData);
          break;
        case 'cards':
          formattedData = formatForCards(processedData);
          break;
        case 'json':
          formattedData = processedData; // JSON displays raw data
          break;
        case 'chart':
          formattedData = formatForChart(processedData);
          break;
        default: // 'list'
          formattedData = formatForList(processedData);
      }
    }

    const result = {
      displayType,
      data: formattedData,
      itemCount: processedData.length,
      originalItemCount: incomingData ? (Array.isArray(incomingData) ? incomingData.length : 1) : 0,
      processedAt: new Date().toISOString()
    };

    if (showMetadata) {
      result.metadata = {
        maxItems,
        truncated: maxItems > 0 && processedData.length > maxItems,
        expectedSchema,
        actualSchema: inferSchema(processedData)
      };
    }

    return result;

  } catch (error) {
    if (params.enableLogging) {
      console.error('Content display error:', error);
    }

    return {
      success: false,
      error: error.message,
      displayType: nodeData.displayType || 'list',
      timestamp: new Date().toISOString()
    };
  }
}

// Helper function to generate sample data
function generateSampleData(expectedSchema) {
  if (!expectedSchema) {
    return [
      { id: 1, title: 'Sample Content 1', body: 'Sample body text', userId: 1 },
      { id: 2, title: 'Sample Content 2', body: 'More sample text', userId: 2 }
    ];
  }

  // Generate based on schema (simplified)
  if (expectedSchema.type === 'array') {
    return Array(3).fill(null).map((_, index) => ({
      id: index + 1,
      title: `Sample Item ${index + 1}`,
      value: Math.random() * 100
    }));
  }

  return [{ sample: true, message: 'No data provided' }];
}

// Formatting functions for different display types
function formatForTable(data) {
  if (!Array.isArray(data) || data.length === 0) return [];

  // Ensure consistent column structure
  const columns = Object.keys(data[0] || {});
  return data.map(item => {
    const row = {};
    columns.forEach(col => {
      row[col] = item[col] !== undefined ? item[col] : '';
    });
    return row;
  });
}

function formatForCards(data) {
  if (!Array.isArray(data)) return [];

  return data.map(item => ({
    ...item,
    cardTitle: item.title || item.name || item.label || `Item ${item.id || 'Unknown'}`,
    cardContent: item.body || item.description || item.content || 'No content available',
    cardMeta: item.userId || item.author || item.category || ''
  }));
}

function formatForList(data) {
  if (!Array.isArray(data)) return [];

  return data.map(item => ({
    ...item,
    listTitle: item.title || item.name || item.label || `Item ${item.id || 'Unknown'}`,
    listSubtitle: item.body || item.description || item.subtitle || ''
  }));
}

function formatForChart(data) {
  if (!Array.isArray(data)) return [];

  // Simple chart formatting - extract numeric values
  return data.map((item, index) => {
    const numericFields = Object.entries(item)
      .filter(([key, value]) => typeof value === 'number')
      .reduce((acc, [key, value]) => ({ ...acc, [key]: value }), {});

    return {
      label: item.title || item.name || item.label || `Item ${index + 1}`,
      ...numericFields,
      x: index,
      y: Object.values(numericFields)[0] || index
    };
  });
}

// Helper to infer data schema
function inferSchema(data) {
  if (!Array.isArray(data) || data.length === 0) {
    return { type: 'array', items: { type: 'object' } };
  }

  const sample = data[0];
  const properties = {};

  Object.entries(sample).forEach(([key, value]) => {
    properties[key] = { type: typeof value };
  });

  return {
    type: 'array',
    items: {
      type: 'object',
      properties
    }
  };
}
